  .cell--space{background:#F6F9FE; color:#B9C7DB;}
  .cell--enter{background:var(--accent-soft); color:var(--accent); font-size:.85rem;}

"""

js_anchor = """        contentEl.querySelectorAll('pre code').forEach(block => {
          const m = (block.className || '').match(/language-([\\w-]+)/);
          const lang = m && m[1];
          if (lang && window.hljs && hljs.getLanguage(lang)){
            hljs.highlightElement(block);
          }
        });
"""
js_insert = """
        // Upgrade ```cells blocks into graph-paper cell rows (one symbol per cell).
        contentEl.querySelectorAll('pre code.language-cells').forEach(block => {
          const wrap = document.createElement('div');
          wrap.className = 'cells';
          block.textContent.replace(/\\n$/, '').split('\\n').forEach(line => {
            const row = document.createElement('div');
            row.className = 'cellrow';
            Array.from(line).forEach(ch => {
              const cell = document.createElement('span');
              cell.className = 'cell' + (ch === ' ' ? ' cell--space' : ch === '\\u21b5' ? ' cell--enter' : '');
              cell.textContent = ch === ' ' ? '\\u00b7' : ch;
              row.appendChild(cell);
            });
            wrap.appendChild(row);
          });
          block.closest('pre').replaceWith(wrap);
        });
"""

files = sorted(pathlib.Path('.').glob('task*/*.html'))
assert len(files) == 9, files
for f in files:
