    assert css_anchor in html and js_anchor in html, f
    assert '.cells{' not in html, f"already patched: {f}"
    html = html.replace(css_anchor, css_insert + css_anchor)
    html = html.replace(js_anchor, js_anchor + js_insert)
    f.write_text(html)
    print("patched", f)
